  if (decidedCases < 12 || decidedCases > accessCases) return { ok: false, metric: decidedCases, label: "decidedCases-bound" };
  if (deniedCases < 4) return { ok: false, metric: deniedCases, label: "deniedCases-depth" };
  if (privacyLeaks > 0) return { ok: false, metric: privacyLeaks, label: "privacyLeaks-present" };
  if (!(decidedCases <= accessCases && deniedCases >= 4 && privacyLeaks === 0)) return { ok: false, metric: decidedCases, label: "invariant" };
